import java.util.Objects;

public class Propietario {
    private String dni;       // ← cambia por los atributos que pidan
    private String nombre;
    private String telefono;

    // Constructor normal
    public Propietario(String dni, String nombre, String telefono) {
        this.dni = dni;
        this.nombre = nombre;
        setTelefono(telefono); // usa el setter para que valide
    }

    // Constructor de copia — siempre igual, solo cambia el nombre de la clase
    public Propietario(Propietario otro) {
        this.dni = otro.dni;
        this.nombre = otro.nombre;
        this.telefono = otro.telefono;
    }

    // Getters
    public String getDni()      { return dni; }
    public String getNombre()   { return nombre; }
    public String getTelefono() { return telefono; }

    // Setters normales
    public void setDni(String dni)       { this.dni = dni; }
    public void setNombre(String nombre) { this.nombre = nombre; }

    // Setter con validación — cambia SOLO la condición del if
    public void setTelefono(String telefono) {
        if (telefono != null && telefono.length() == 9) { // ← cambia esta condición
            this.telefono = telefono;
        }
        // Si no cumple, no hace nada
    }

    // equals — cambia SOLO el campo de comparación (aquí: dni)
    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (obj == null || getClass() != obj.getClass()) return false;
        Propietario that = (Propietario) obj;
        return Objects.equals(dni, that.dni); // ← cambia dni por el campo que pidan
    }

    // hashCode — usa el mismo campo que equals
    @Override
    public int hashCode() {
        return Objects.hash(dni); // ← mismo campo que equals
    }

    @Override
    public String toString() {
        return "Propietario[dni=" + dni + ", nombre=" + nombre + ", telefono=" + telefono + "]";
    }
}

public class Mascota implements Informable {
    private String nombre;
    private String especie;
    private int edad;
    private Propietario propietario; // ← clase del ejercicio anterior

    // ↓ static: existe UNA sola vez para toda la clase, no por objeto
    private static int totalMascotas = 0;

    public Mascota(String nombre, String especie, int edad, Propietario propietario) {
        this.nombre = nombre;
        this.especie = especie;
        setEdad(edad);
        this.propietario = propietario;
        totalMascotas++; // ← SIEMPRE dentro del constructor
    }

    // Setter con validación
    public void setEdad(int edad) {
        if (edad >= 0) { this.edad = edad; } // ← cambia la condición
    }

    // Método boolean — nombre y condición según enunciado
    public boolean esCachorro() { return edad < 2; }

    // Método estático — se llama como Mascota.getTotalMascotas()
    public static int getTotalMascotas() { return totalMascotas; }

    // Getters y setters normales...
    public String getNombre()           { return nombre; }
    public String getEspecie()          { return especie; }
    public int getEdad()                { return edad; }
    public Propietario getPropietario() { return propietario; }

    @Override
    public String toString() {
        // OJO: usa propietario.getNombre(), NO propietario.toString()
        return "Mascota[nombre=" + nombre + ", especie=" + especie +
               ", edad=" + edad + ", propietario=" + propietario.getNombre() + "]";
    }

    @Override
    public String generarInforme() {
        String estado = esCachorro() ? "Cachorro" : "Adulto";
        return "Mascota: " + nombre + " (" + especie + ") - " + estado +
               " | Propietario: " + propietario.getNombre();
    }
}

// ═══ Empleado.java ══════════════════════════════════════
public abstract class Empleado {
    protected String nombre;        // protected = las subclases pueden acceder
    protected double salarioBase;

    public Empleado(String nombre, double salarioBase) {
        this.nombre = nombre;
        this.salarioBase = salarioBase;
    }

    abstract double calcularSalario(); // sin cuerpo — cada subclase lo implementa

    @Override
    public String toString() {
        return String.format("[Empleado] %s | Salario: %.2f EUR", nombre, calcularSalario());
    }
}


// ═══ Veterinario.java ═══════════════════════════════════
public class Veterinario extends Empleado implements Informable, Comparable<Veterinario> {
    private String especialidad;

    public Veterinario(String nombre, double salarioBase, String especialidad) {
        super(nombre, salarioBase); // ← PRIMERA LÍNEA obligatoria
        this.especialidad = especialidad;
    }

    @Override
    double calcularSalario() { return salarioBase + 500.0; }

    @Override
    public String toString() {
        return String.format("[Veterinario] %s (%s) | Salario: %.2f EUR",
                             nombre, especialidad, calcularSalario());
    }

    @Override
    public String generarInforme() {
        return "Veterinario: " + nombre + " | Especialidad: " + especialidad +
               String.format(" | Salario: %.2f", calcularSalario());
    }

    @Override
    public int compareTo(Veterinario otro) {
        return Double.compare(this.calcularSalario(), otro.calcularSalario());
    }
}


// ═══ Auxiliar.java ══════════════════════════════════════
public class Auxiliar extends Empleado {
    private String turno;

    public Auxiliar(String nombre, double salarioBase, String turno) {
        super(nombre, salarioBase); // ← PRIMERA LÍNEA obligatoria
        this.turno = turno;
    }

    @Override
    double calcularSalario() {
        if ("noche".equalsIgnoreCase(turno)) return salarioBase * 1.20;
        return salarioBase;
    }

    @Override
    public String toString() {
        return String.format("[Auxiliar] %s (%s) | Salario: %.2f EUR",
                             nombre, turno, calcularSalario());
    }
}


