public static <T extends Comparable<T>> void mostrarMayor(T a, T b) {
    int resultado = a.compareTo(b);
    if (resultado > 0)      System.out.println("El mayor es: " + a);
    else if (resultado < 0) System.out.println("El mayor es: " + b);
    else                    System.out.println("Ambos son iguales.");
}

