// Padre
public abstract class Padre {
    protected String atrib1;
    protected double atrib2;
    public Padre(String a1, double a2) { this.atrib1 = a1; this.atrib2 = a2; }
    abstract double calcular();  // ← sin cuerpo, con ;
}

// Hijo
public class Hijo extends Padre {
    private String extra;
    public Hijo(String a1, double a2, String extra) {
        super(a1, a2);  // ← PRIMERA LÍNEA siempre
        this.extra = extra;
    }
    @Override
    double calcular() { return atrib2 + 500; } // ← fórmula que pida el enunciado
}

